// AnnotationListSidebar.js

import React from 'react';
import './AnnotationListSidebar.css';

export default function AnnotationListSidebar({
  annotations,
  onDeleteAnnotation,
  onUpdateAnnotation,
  labelClasses
}) {
  // 1) This function is called when user changes the dropdown label for a given annotation
  const handleLabelDropdown = (idx, newLabel) => {
    // Find the color in labelClasses that corresponds to the new label
    const newColor = labelClasses.find((lc) => lc.name === newLabel)?.color || '#ff0000';

    // Update BOTH label and color in the parent (Annotate.js) state
    onUpdateAnnotation(idx, {
      label: newLabel,
      color: newColor
    });
  };

  return (
    <div className="anno-sidebar">
      <h3>Annotations</h3>
      {annotations.length === 0 && <p>No annotations yet.</p>}

      {annotations.map((ann, i) => {
        const label = ann.label || '';

        return (
          <div key={i} className="anno-item">
            <div>
              <span className="shape-type">{ann.type.toUpperCase()}</span>{' '}
              <span className="shape-label">{label}</span>
            </div>
            <div className="anno-actions">
              <select
                value={label}
                onChange={(e) => handleLabelDropdown(i, e.target.value)}
              >
                {labelClasses.map((lc, idx) => (
                  <option key={idx} value={lc.name}>
                    {lc.name}
                  </option>
                ))}
              </select>
              <button onClick={() => onDeleteAnnotation(i)}>Del</button>
            </div>
          </div>
        );
      })}
    </div>
  );
}
